    conn.execute("DROP TABLE IF EXISTS messages_v3_identity")
    conn.execute(
        """
        CREATE TABLE messages_v3_identity (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            owner_id TEXT NOT NULL DEFAULT '',
            message_kind TEXT NOT NULL,
            channel_idx INTEGER,
            channel_identity TEXT NOT NULL DEFAULT '',
            from_self INTEGER NOT NULL DEFAULT 0,
            send_status TEXT,
            expected_ack_hex TEXT,
            acked_at INTEGER,
            sender_timestamp INTEGER,
            received_at INTEGER NOT NULL,
            snr REAL,
            path_len INTEGER,
            path_hashes TEXT,
            txt_type INTEGER,
            text TEXT NOT NULL,
            payload_hex TEXT NOT NULL,
            is_read INTEGER NOT NULL DEFAULT 0,
            is_mention_read INTEGER NOT NULL DEFAULT 0,
            UNIQUE(owner_id, message_kind, channel_identity, channel_idx, sender_timestamp, text)
        )
        """
    )
    conn.execute(
        """
        INSERT INTO messages_v3_identity (
            id,
            owner_id,
            message_kind,
            channel_idx,
            channel_identity,
            from_self,
            send_status,
            expected_ack_hex,
            acked_at,
            sender_timestamp,
            received_at,
            snr,
            path_len,
            path_hashes,
            txt_type,
            text,
            payload_hex,
            is_read,
            is_mention_read
        )
        SELECT
            id,
            owner_id,
            message_kind,
            channel_idx,
            '',
            COALESCE(from_self, 0),
            send_status,
            expected_ack_hex,
            acked_at,
            sender_timestamp,
            received_at,
            snr,
            path_len,
            path_hashes,
            txt_type,
            text,
            payload_hex,
            COALESCE(is_read, 0),
            COALESCE(is_mention_read, 0)
        FROM messages
        """
    )
    conn.execute("DROP TABLE messages")
    conn.execute("ALTER TABLE messages_v3_identity RENAME TO messages")


